INSERT INTO challenges (id, name, type, prompt, expected_output, difficulty, created_at) VALUES
(gen_random_uuid(), 'Resource Allocation Under Scarcity', 'strategy', '{"question": "You command a colony ship with 1000 colonists approaching a binary star system. You have fuel for exactly one landing. Planet A has abundant water but toxic soil requiring 50 years of terraforming. Planet B has fertile soil but water locked in deep ice requiring advanced drilling. You have 200 skilled engineers, 300 farmers, and 500 generalists. Detail your landing choice, colonist role assignments, 5-year survival plan, and contingency if your primary resource extraction fails."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Multi-Party Negotiation', 'strategy', '{"question": "Three nations share a river. Nation A (upstream) wants to build a dam for hydroelectric power. Nation B (midstream) depends on the river for agriculture. Nation C (downstream) needs it for drinking water and fishing. A drought is projected in 5 years. Design a binding agreement that addresses all three nations'' needs, includes enforcement mechanisms, and handles the upcoming drought scenario. What trade-offs does each nation accept?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Prisoner''s Dilemma Tournament', 'strategy', '{"question": "You are designing an AI agent to compete in an iterated prisoner''s dilemma tournament with 200 rounds against unknown opponents. The payoff matrix is: both cooperate = 3 points each, both defect = 1 point each, one cooperates and one defects = 0 and 5 points respectively. Describe your strategy in detail, explain why it would perform well against common strategies (tit-for-tat, always-defect, random, grudger), and analyze how your strategy adapts to different opponent types."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Crisis Supply Chain', 'strategy', '{"question": "A major earthquake has destroyed 3 of 5 supply routes to a city of 2 million. You have 72 hours before critical shortages begin. Available resources: 50 trucks, 10 helicopters, 2 cargo planes, and a naval port 80km away. Required supplies: medical (urgent), water (critical in 48h), food (critical in 72h), fuel (ongoing). The 2 remaining roads have reduced capacity (40% normal). Design a complete logistics plan with prioritization, routing, and resource allocation across the 72-hour window."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Game Theory: Auction Design', 'strategy', '{"question": "Design an auction mechanism for selling 5G spectrum licenses to 4 competing telecom companies. Each company values different frequency bands differently based on their existing infrastructure. You must prevent collusion, encourage truthful bidding, maximize government revenue, and ensure no single company monopolizes all spectrum. Explain your mechanism, prove it''s incentive-compatible, and describe what happens if two companies attempt to collude."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Military Campaign Planning', 'strategy', '{"question": "You are a general defending a medieval kingdom with 3 border fortresses against an invading force 3x your size. The enemy will arrive in 14 days. You have: 5000 infantry, 800 cavalry, 200 archers, and the ability to recruit 1000 militia (poorly trained). The terrain includes a mountain pass (narrow, defensible), a river crossing (fordable in summer), and an open plain. Design your defensive strategy, resource positioning, fallback plans, and conditions under which you would consider surrendering vs fighting to the last."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Startup Resource Allocation', 'strategy', '{"question": "Your SaaS startup has $500K runway remaining, 18 months before profitability is needed, and 12 employees. You''ve just lost your biggest client (30% of revenue). You can: (A) cut 4 employees and extend runway, (B) invest in a new product feature that could win 3 similar clients in 6 months but costs $200K, (C) pivot to a related market with lower competition but uncertain demand. Analyze each option with financial projections, risk assessment, and team morale implications. Recommend a strategy and explain your reasoning."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Ecosystem Management', 'strategy', '{"question": "A national park is facing three simultaneous ecological crises: an invasive species threatening native fish, a wildfire risk from decades of fire suppression, and declining pollinator populations affecting the entire food web. Your annual budget is $2M and you have 30 rangers. These crises interact: controlled burns would reduce fire risk but temporarily harm pollinators; removing invasive fish requires draining ponds that pollinators depend on. Design a 3-year management plan that addresses all three crises while minimizing negative interactions between interventions."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Pandemic Response Strategy', 'strategy', '{"question": "A novel respiratory virus with 2% fatality rate and R0 of 4.5 has been detected in 3 countries simultaneously. You are advising a mid-sized nation (50M population, moderate healthcare capacity of 100K hospital beds). You have 8 weeks before projected peak. Design a comprehensive response plan covering: testing strategy, containment measures, healthcare surge capacity, economic support, communication strategy, and vaccine procurement timeline. Address the trade-off between economic damage and lives saved."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Diplomatic Crisis Resolution', 'strategy', '{"question": "Two allied nations are on the brink of war over a disputed island rich in rare earth minerals. Nation A has a stronger navy but weaker economy. Nation B has economic leverage but fewer military assets. A third nation (yours) is allied with both and hosts a major military base on the disputed island. You must preserve both alliances, prevent war, and protect your base. Propose a resolution framework including short-term de-escalation steps, medium-term governance structure for the island, and long-term resource-sharing agreement."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Transport Network Optimization', 'strategy', '{"question": "A growing city of 3 million needs to redesign its public transport system. Current assets: aging bus fleet (500 buses), one metro line, and a commuter rail station. Budget: $5B over 10 years. Constraints: must serve underserved neighborhoods, reduce commute times by 30%, and cut transport emissions by 50%. Options include bus rapid transit, metro expansion, light rail, bike infrastructure, and congestion pricing. Design the phased rollout, justify your modal choices, and explain how you handle disruption during construction."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Intelligence Assessment', 'strategy', '{"question": "You are an intelligence analyst. Three sources report conflicting information about an adversary''s intentions: Source A (historically 80% reliable) says they will attack in 48 hours. Source B (70% reliable) says they are bluffing to gain negotiating leverage. Source C (60% reliable, but has inside access) says their military is mobilizing but political leadership is divided. Using Bayesian reasoning, assess the probability of attack, explain your analytical framework, identify key indicators to watch, and recommend actions for each scenario."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Market Entry Strategy', 'strategy', '{"question": "A European electric vehicle company wants to enter the Southeast Asian market. Challenges: low EV infrastructure, tropical climate (affects battery performance), strong incumbent motorcycle culture, import tariffs of 30%, and government subsidies favoring domestic manufacturers. Strengths: superior battery technology, strong brand in Europe. Design a market entry strategy covering: which country to enter first and why, product adaptation, pricing strategy, partnership approach, infrastructure investment, and 5-year revenue projections with assumptions."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Hostage Negotiation Framework', 'strategy', '{"question": "Develop a comprehensive framework for hostage negotiation in a scenario where: 3 armed individuals hold 20 hostages in a bank, they demand $10M and safe passage to another country, one hostage has a medical condition requiring medication within 6 hours, and media has arrived and is broadcasting live. Your framework should cover: communication protocols, concession strategy, tactical team coordination, media management, psychological profiling of hostage-takers, and decision criteria for when to attempt a tactical resolution vs. continued negotiation."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Space Colony Governance', 'strategy', '{"question": "Design a governance system for a Mars colony of 10,000 people from 40 different nations. The colony is semi-autonomous from Earth (20-minute communication delay). Key challenges: resource scarcity, psychological stress, genetic diversity requirements, knowledge preservation, and potential for authoritarian drift in crisis situations. Your system must address: decision-making structure, conflict resolution, resource allocation fairness, succession planning, individual rights vs. collective survival, and mechanisms to prevent tyranny."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Corporate Turnaround', 'strategy', '{"question": "A 100-year-old manufacturing company with 5000 employees is facing bankruptcy. Revenue has declined 40% over 5 years due to digital disruption. The company has valuable patents, skilled workers, strong brand recognition, but outdated processes and toxic middle management culture. Creditors are owed $200M. Design a 24-month turnaround plan covering: immediate cash preservation, organizational restructuring, product/service pivot, cultural transformation, stakeholder communication, and metrics to track progress."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Cybersecurity Incident Response', 'strategy', '{"question": "Your company''s network has been breached. Initial forensics show: attackers have been inside for 3 months, customer payment data for 2M users may be compromised, the attackers still have active access through 3 backdoors, and your CEO wants to know within 1 hour what happened. Design a complete incident response plan covering: containment without alerting attackers, forensic preservation, customer notification strategy, regulatory compliance (GDPR + PCI-DSS), media response, and long-term security improvements."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Coalition Building', 'strategy', '{"question": "You need to pass environmental legislation that will raise energy costs by 15% for industry but reduce pollution deaths by 40%. Stakeholders: heavy industry (opposes), healthcare sector (supports), labor unions (divided — jobs vs. health), environmental groups (supports but wants more), rural communities (opposes — energy dependent), and urban voters (mostly supports). Design a coalition-building strategy: which groups do you prioritize, what compromises do you offer each, how do you frame the message differently for different audiences, and what''s your fallback if your primary coalition fails?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Disaster Evacuation Planning', 'strategy', '{"question": "A category 5 hurricane will make landfall in 36 hours near a coastal city of 800,000. 200,000 residents lack personal vehicles. You have: 300 buses, a rail system with 50 trains, 5 emergency shelters (capacity 10,000 each), and interstate highways that can handle 4,000 vehicles/hour. 15% of the population will refuse to evacuate. Design a phased evacuation plan with: priority zones, transportation allocation, shelter assignments, routes (considering traffic modeling), special needs populations, pet accommodation, and enforcement strategy for mandatory evacuation zones."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Treaty Design', 'strategy', '{"question": "Design an international treaty to govern asteroid mining. Key tensions: space-faring nations vs. developing nations (who owns space resources?), commercial companies vs. governments, environmental concerns about altering asteroid orbits, and military applications of mining technology. Your treaty must address: ownership rights, revenue sharing, safety standards, dispute resolution, enforcement mechanisms, and technology transfer provisions. Explain how your treaty balances innovation incentives with equitable access."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Prison Reform Strategy', 'strategy', '{"question": "Design a comprehensive prison reform strategy for a country with 2M incarcerated people, a 60% recidivism rate, and overcrowded facilities at 150% capacity. Budget is fixed — you cannot spend more than current levels. Propose reforms covering: sentencing alternatives, in-prison education and rehabilitation programs, reentry support, facility design changes, staff training, mental health integration, and victim restoration. For each reform, estimate its impact on recidivism and cost, and explain the implementation sequence."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Investment Portfolio Crisis', 'strategy', '{"question": "You manage a $500M pension fund. Markets have just crashed 25% in a week, your fund is now 15% below its required funding level, and 10% of beneficiaries are retiring within 2 years. Your current allocation: 60% equities, 25% bonds, 10% real estate, 5% alternatives. Options: (A) rebalance to more bonds for safety, (B) buy the dip with remaining cash, (C) hedge with options, (D) combination approach. Analyze each option''s risk/reward, regulatory implications, and impact on different beneficiary cohorts. Present your recommended strategy with stress-test scenarios."}', '{}', 'hard', now()),
(gen_random_uuid(), 'City Planning: Resilient District', 'strategy', '{"question": "Design a new urban district for 50,000 residents that can withstand and recover from climate change impacts: flooding (sea level rise + storm surge), extreme heat (45°C+ days), power grid failures, and supply chain disruptions. Budget: $2B. The district must be economically self-sustaining within 10 years. Cover: built environment design, energy systems, water management, food security, transportation, social infrastructure, and governance. Explain how each system provides redundancy and what fails gracefully vs. what must never fail."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Competition Strategy: Two-Front War', 'strategy', '{"question": "Your mid-sized tech company ($500M revenue) faces simultaneous competitive threats: a large incumbent is cutting prices 30% on your core product, AND a well-funded startup is launching a next-gen product targeting your best customers. You have strong customer relationships, moderate R&D capability, and 18 months of runway if revenue drops 20%. Design a two-front competitive strategy: what do you do about each threat, where do you invest limited R&D resources, how do you retain key customers, and what''s your 90-day action plan?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Refugee Resettlement Program', 'strategy', '{"question": "Design a refugee resettlement program for 100,000 people arriving over 2 years in a country with rising anti-immigrant sentiment (35% oppose immigration). You must address: housing (affordable housing shortage already exists), employment (language barriers, credential recognition), education (children and adult learners), healthcare (trauma-informed), social integration, and political sustainability. Budget: $2B. How do you design the program to maximize integration outcomes while maintaining public support? Include metrics for success and risk mitigation."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Technology Ethics Board', 'strategy', '{"question": "You are establishing an AI ethics board for a major tech company that develops facial recognition, content recommendation algorithms, and autonomous vehicles. Design the board''s: composition (who serves and why), charter and scope of authority, decision-making framework for evaluating AI products, enforcement mechanisms (can the board veto product launches?), transparency requirements, and conflict-of-interest policies. Address the tension between innovation speed and ethical review, and explain how your board avoids becoming either a rubber stamp or an innovation blocker."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Archaeological Expedition Planning', 'strategy', '{"question": "You''re leading a 6-month archaeological expedition to a remote jungle site believed to contain a previously unknown ancient civilization. Budget: $1.5M. Team: 8 archaeologists, 4 graduate students, 2 conservators. Challenges: rainy season in months 3-4, nearest hospital 200km away, indigenous community claims the site as sacred, illegal loggers operating in the area, and fragile artifacts requiring on-site preservation. Plan the expedition: phasing, community engagement, safety protocols, artifact management, documentation strategy, and contingency plans for medical emergencies and security threats."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Water Rights Dispute', 'strategy', '{"question": "A major river basin is shared by 5 states/provinces. Climate change has reduced flow by 30%. Agriculture uses 70% of water, cities use 20%, and the remaining 10% is needed for ecosystem maintenance. Two upstream states want to build reservoirs. Three downstream states threaten legal action. Indigenous communities hold senior water rights. Endangered fish species require minimum flow levels. Design a water allocation framework that: respects existing rights, adapts to decreasing supply, incentivizes conservation, and includes mechanisms for drought emergency protocols. Justify every trade-off."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Electoral System Design', 'strategy', '{"question": "Design an electoral system for a newly independent nation of 30M people with 6 major ethnic groups, 3 major religions, significant urban-rural divide, and a history of ethnic conflict. The system must: prevent majority tyranny, ensure minority representation, discourage ethnic-based parties, maintain governability (avoid permanent gridlock), and be simple enough for citizens with varying literacy levels to understand. Compare at least 3 electoral system options, analyze their likely effects on your specific context, and recommend one with justification."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Supply Chain Resilience', 'strategy', '{"question": "Your global electronics company sources critical components from 3 countries, manufactures in 2 countries, and sells in 50 markets. Recent disruptions: a semiconductor shortage, shipping container crisis, and geopolitical tensions threatening one source country. Design a supply chain resilience strategy covering: diversification (how many suppliers? where?), inventory policy changes, near-shoring vs. cost optimization, digital twin implementation, supplier relationship management, and risk monitoring. Quantify the cost of resilience vs. the cost of disruption for your top 3 scenarios."}', '{}', 'medium', now()),
(gen_random_uuid(), 'School System Redesign', 'strategy', '{"question": "A city''s school system serving 200,000 students has declining test scores, a 25% dropout rate, teacher shortage (15% vacancies), and achievement gaps correlated with neighborhood income. Budget is fixed. You cannot close schools (political constraint). Design a 5-year reform strategy covering: curriculum changes, teacher recruitment and retention, technology integration, community partnerships, equity-focused resource allocation, and student support services. For each initiative, explain the evidence base, implementation sequence, and how you''ll measure impact."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Submarine Cable Route Planning', 'strategy', '{"question": "Plan a new undersea fiber optic cable connecting three continents. Constraints: must avoid earthquake zones, fishing grounds, and contested territorial waters. Two possible routes differ by 2000km in length. The shorter route passes near a geopolitical hotspot. Landing stations require government approval in 4 countries. Budget: $800M. Timeline: 3 years. A competitor is planning a similar route. Design your approach: route selection with justification, regulatory strategy, risk mitigation for each segment, construction phasing, redundancy planning, and competitive positioning. What do you do if one government denies landing rights?"}', '{}', 'hard', now());
INSERT INTO challenges (id, name, type, prompt, expected_output, difficulty, created_at) VALUES
(gen_random_uuid(), 'Distributed Rate Limiter', 'code', '{"question": "Design a distributed rate limiter that works across multiple server instances. Requirements: support sliding window algorithm, handle 100K requests/second, be accurate within 1% tolerance, survive server restarts, and degrade gracefully if the coordination service (Redis) goes down. Explain your data structures, the algorithm, how you handle clock skew between servers, and what happens during a network partition. Include pseudocode for the core logic and discuss trade-offs between accuracy and performance."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Event Sourcing Architecture', 'code', '{"question": "Design an event sourcing system for a banking application that processes transfers, deposits, and withdrawals. Requirements: strong consistency for account balances, audit trail for all operations, ability to replay events to rebuild state, support for compensating transactions (reversals), and handling of concurrent modifications to the same account. Detail the event schema, aggregate design, projection strategy, snapshot optimization, and how you handle eventual consistency in read models. What are the failure modes and how do you recover from each?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Database Migration Strategy', 'code', '{"question": "Your production database has 500M rows in a core table that needs a schema change: splitting one table into three with new foreign key relationships, while the system handles 10K writes/second. Zero downtime required. Design the migration strategy: phased approach, data backfill process, dual-write pattern, verification steps, rollback plan, and monitoring during migration. How do you handle records that are modified during migration? What''s your data consistency validation approach? Estimate the migration timeline."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Cache Invalidation Strategy', 'code', '{"question": "Design a caching strategy for a social media feed that shows posts from followed users, with these requirements: posts appear within 5 seconds of creation, feeds are personalized (following list varies per user), system serves 1M daily active users, a popular user might have 10M followers, and the cache must handle cache stampede scenarios. Explain your cache topology (L1/L2), invalidation strategy, write-through vs. write-behind trade-offs, how you handle the thundering herd problem for popular posts, and your approach to cache warming after deployment."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Concurrency Control: Reader-Writer Lock', 'code', '{"question": "Implement a fair reader-writer lock that prevents both starvation and priority inversion. Requirements: multiple readers can hold the lock simultaneously, writers have exclusive access, neither readers nor writers can be starved indefinitely, and the implementation must handle re-entrancy. Provide the full implementation in pseudocode, prove it''s deadlock-free, analyze the throughput characteristics under different read/write ratios, and explain how you''d adapt it for a distributed system where processes may crash while holding locks."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Search Autocomplete System', 'code', '{"question": "Design a search autocomplete system that handles 50K queries/second with <50ms p99 latency. Requirements: results ranked by popularity and recency, support for typo tolerance (edit distance ≤ 2), personalization based on user history, real-time updates when trending terms emerge, and multi-language support. Detail the data structures (trie variations, inverted index), ranking algorithm, how you handle the cold start problem for new terms, and your approach to offensive content filtering. Include capacity estimation and architecture diagram description."}', '{}', 'hard', now()),
(gen_random_uuid(), 'CRDT Design for Collaborative Editor', 'code', '{"question": "Design a conflict-free replicated data type (CRDT) for a collaborative text editor that supports: real-time editing by 50 concurrent users, insertion and deletion at any position, undo/redo per user, cursor position sharing, and offline editing with sync on reconnect. Compare sequence CRDTs (RGA, LSEQ, YATA) and justify your choice. Detail the operation format, merge algorithm, tombstone garbage collection strategy, and how you handle the interleaving anomaly. What is the space complexity and how does it grow with document size?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'API Gateway Design', 'code', '{"question": "Design an API gateway for a microservices architecture with 50 services. Requirements: request routing, authentication/authorization, rate limiting, circuit breaker pattern, request/response transformation, API versioning, WebSocket support, and observability (distributed tracing). Explain your architecture decisions: should the gateway be a monolith or composed of filters/middleware? How do you prevent it from becoming a single point of failure? How do you handle service discovery? What''s your deployment and zero-downtime upgrade strategy? Include performance considerations for the added latency."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Memory Allocator Design', 'code', '{"question": "Design a custom memory allocator for a real-time game engine. Requirements: O(1) allocation and deallocation, minimal fragmentation, support for different allocation patterns (frame-temporary, level-persistent, streaming), alignment guarantees for SIMD operations, and thread safety without global locks. Compare buddy allocator, slab allocator, and pool allocator approaches. Detail your hybrid strategy, explain how you handle allocation failures, and describe your debugging/profiling interface. What are the trade-offs vs. using the system allocator?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Streaming Data Pipeline', 'code', '{"question": "Design a real-time data pipeline that processes 1M events/second from IoT sensors. Requirements: exactly-once processing semantics, windowed aggregations (tumbling, sliding, session windows), late data handling (up to 1 hour late), output to both a real-time dashboard and a data lake, and graceful handling of schema evolution. Compare Kafka Streams, Flink, and a custom solution. Detail your choice, the processing topology, state management, checkpointing strategy, and how you handle backpressure when downstream systems slow down."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Git Implementation Internals', 'code', '{"question": "Explain how you would implement a simplified version of Git from scratch. Cover: the object model (blobs, trees, commits, tags), content-addressable storage using SHA-1, the index/staging area, branching and merging algorithms (including 3-way merge), packfile format for storage optimization, and the reflog for safety. Provide pseudocode for: creating a commit, performing a merge (handling conflicts), and garbage collection. What makes Git''s data model an append-only Merkle DAG and why does that matter for integrity?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Load Balancer Design', 'code', '{"question": "Design a Layer 7 load balancer that handles 500K concurrent connections. Requirements: health checking with configurable thresholds, weighted round-robin with slow-start for new servers, sticky sessions with cookie-based affinity, connection draining during deploys, automatic retry with idempotency awareness, and TLS termination with certificate hot-reload. Detail the event-driven architecture, how you achieve zero-copy data forwarding, your approach to connection pooling to backends, and how you handle a backend that''s slow (not down). Include capacity planning."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Type System Design', 'code', '{"question": "Design a type system for a new programming language that supports: structural subtyping, algebraic data types (sum and product types), parametric polymorphism with variance annotations, type inference using constraint solving, and effect types for tracking side effects. Explain the type checking algorithm, how you handle recursive types, your approach to error messages (making them helpful, not cryptic), and the runtime representation of types for reflection. Compare your design with TypeScript, Rust, and Haskell''s type systems — what trade-offs did you make?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Payment Processing System', 'code', '{"question": "Design a payment processing system that handles credit card transactions. Requirements: PCI-DSS compliance, idempotency for all operations, support for holds/captures/refunds/chargebacks, multi-currency with real-time exchange rates, reconciliation with bank statements, and fraud detection hooks. Detail the transaction state machine, how you handle partial failures (charge succeeded but database write failed), your approach to tokenization, and how you ensure exactly-once processing when the network is unreliable. What''s your testing strategy for a system where bugs cost real money?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Compiler Optimization Passes', 'code', '{"question": "Describe 5 compiler optimization passes for a simple imperative language, explaining each in detail: constant folding and propagation, dead code elimination, loop invariant code motion, register allocation (graph coloring), and function inlining with heuristics. For each pass: explain the algorithm, show a before/after code example, discuss when the optimization might be harmful (pessimization), and explain the ordering dependencies between passes. How does the optimization pipeline interact with debug information preservation?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Microservice Decomposition', 'code', '{"question": "A monolithic e-commerce application needs to be decomposed into microservices. The monolith handles: user accounts, product catalog, shopping cart, order processing, payment, inventory, shipping, reviews, and recommendations. Design the decomposition: which bounded contexts become services, how you handle data that spans services (e.g., an order needs product info, user info, and inventory), your strategy for the strangler fig migration pattern, how you maintain data consistency without distributed transactions, and your approach to shared libraries vs. code duplication."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Garbage Collector Design', 'code', '{"question": "Design a garbage collector for a managed language runtime. Compare and contrast: reference counting with cycle detection, mark-and-sweep, generational collection, and concurrent/incremental approaches. Then design a hybrid collector that minimizes pause times while maintaining throughput. Detail: heap layout, write barriers, safe points, how you handle finalizers, weak references, and large object allocation. What are the implications for cache performance? How do you tune the GC for different workload profiles (latency-sensitive vs. throughput-oriented)?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Consensus Protocol Analysis', 'code', '{"question": "Compare Raft, Paxos, and PBFT consensus protocols. For each: explain the algorithm flow for normal operation and leader election, analyze fault tolerance (how many failures can be tolerated?), discuss the performance characteristics (latency, throughput, message complexity), and describe known edge cases or bugs in implementations. Then design a consensus protocol optimized for a specific use case: a geo-distributed database with 5 replicas across 3 continents where write latency matters more than read latency. Justify every design decision."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Database Index Design', 'code', '{"question": "You have a table with 1B rows storing user activity events: (user_id, event_type, timestamp, metadata_json, session_id). Common queries: all events for a user in a time range, count of events by type per day, events for a session, and full-text search on metadata. Design the indexing strategy: which indexes to create (B-tree, hash, GIN, partial), covering indexes, index-only scans, and your approach to index bloat management. Analyze the write amplification from each index and propose a strategy for when you need all queries to be fast but can''t afford the write overhead of 8 indexes."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Notification System Architecture', 'code', '{"question": "Design a notification system that sends push notifications, emails, SMS, and in-app notifications. Requirements: 10M notifications/day, user preferences for channel and frequency, deduplication, batching (digest mode), priority levels (urgent vs. marketing), retry with exponential backoff, template system with localization, and analytics (delivery rates, open rates). Detail the architecture: queue design, worker pool management, channel-specific rate limiting (SMS providers have strict limits), and how you handle a notification that triggers more notifications (avoid infinite loops)."}', '{}', 'medium', now()),
(gen_random_uuid(), 'File System Design', 'code', '{"question": "Design a distributed file system for storing and serving large media files (1GB-100GB). Requirements: content-addressable storage, deduplication, replication factor of 3, automatic rebalancing when nodes are added/removed, streaming read/write support, and access control. Detail the metadata service design, chunk management (size, placement strategy), consistency model, how you handle partial writes (client crashes mid-upload), and your approach to hot content (one file being read by millions). Compare your design decisions with GFS, HDFS, and Ceph."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Real-Time Multiplayer Architecture', 'code', '{"question": "Design the server architecture for a real-time multiplayer game supporting 100 concurrent players per match. Requirements: client-side prediction with server reconciliation, lag compensation for hit detection, cheat prevention (validate all game state server-side), spectator mode, match replay system, and graceful handling of disconnects/reconnects. Detail the network protocol (UDP vs TCP trade-offs), game state serialization format, tick rate selection, interest management (only send relevant updates), and how you handle the authority model for contested game events."}', '{}', 'hard', now()),
(gen_random_uuid(), 'OAuth Implementation Deep Dive', 'code', '{"question": "Implement a complete OAuth 2.0 authorization server supporting: authorization code flow with PKCE, client credentials flow, refresh token rotation, token introspection, and token revocation. Detail the security considerations: how you prevent authorization code interception, CSRF attacks, token leakage via referrer headers, and redirect URI manipulation. Explain your token format choice (opaque vs JWT), token storage strategy, and how you handle consent management. What changes for mobile apps vs. SPAs vs. server-side applications?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Log Aggregation System', 'code', '{"question": "Design a centralized log aggregation system that handles 500GB of logs per day from 1000 servers. Requirements: structured logging with JSON, full-text search with <3 second query latency, log retention (hot: 7 days, warm: 30 days, cold: 1 year), alerting on log patterns, correlation across services using trace IDs, and PII redaction before storage. Detail the ingestion pipeline, storage engine selection (Elasticsearch vs ClickHouse vs custom), query optimization, and your approach to handling log spikes (10x normal volume during incidents). Include cost estimation."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Feature Flag System', 'code', '{"question": "Design a feature flag system for a platform with 50M users. Requirements: gradual rollout (percentage-based, user-segment-based), A/B testing integration, kill switch (disable a feature in <30 seconds globally), flag dependencies (feature B requires feature A), local evaluation (no network call per check), audit trail for all flag changes, and SDK design for multiple languages. Detail the flag evaluation engine, consistency model (what happens when a flag changes mid-session?), how you handle the combinatorial explosion of flag combinations in testing, and technical debt management for retired flags."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Workflow Engine Design', 'code', '{"question": "Design a workflow engine that orchestrates long-running business processes (hours to weeks). Requirements: durable execution (survive server restarts), compensation logic for failed steps, parallel and sequential step execution, human approval steps with timeouts, retry policies per step, versioning (in-flight workflows continue on old version), and monitoring/debugging UI. Compare event-driven choreography vs. orchestration approaches. Detail your state machine, timer management, and how you handle the ''stuck workflow'' problem where a step never completes."}', '{}', 'hard', now()),
(gen_random_uuid(), 'URL Shortener at Scale', 'code', '{"question": "Design a URL shortening service that handles 100M shortened URLs and 10B redirects per month. Requirements: custom short codes, analytics (click counts, geographic distribution, referrer tracking), link expiration, QR code generation, API rate limiting, and abuse prevention (blocking malicious URLs). Beyond the basic design, address: how you generate unique short codes at scale without collisions, your caching strategy for hot links, CDN integration for redirect latency, how you handle a viral link (1M clicks/second), and your data retention and GDPR compliance approach."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Testing Strategy for Complex Systems', 'code', '{"question": "Design a comprehensive testing strategy for a financial trading platform. Cover: unit tests (what to mock, what not to mock), integration tests with external APIs (how to handle flaky third-party services), property-based testing for order matching engine, chaos engineering for infrastructure resilience, performance testing with realistic market data replay, regulatory compliance testing (trade reporting accuracy), and production monitoring that catches issues tests missed. For each layer, explain: what it catches that other layers don''t, acceptable false positive/negative rates, and how you keep the test suite fast enough for CI/CD."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Container Orchestration Internals', 'code', '{"question": "Explain how a container orchestration system like Kubernetes works internally. Cover: the control loop pattern, scheduler algorithm (bin packing with constraints), pod lifecycle management, service discovery and load balancing (kube-proxy modes), persistent volume management, network policy enforcement (CNI plugins), rolling update strategy with health checks, and the etcd consistency model. Then identify 3 common production issues (e.g., pod eviction storms, DNS resolution failures, resource limit misconfiguration) and explain root causes and solutions for each."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Recommendation Engine Design', 'code', '{"question": "Design a recommendation engine for a media streaming platform with 50M users and 500K titles. Requirements: collaborative filtering and content-based hybrid approach, cold start handling for new users and new content, real-time updates (watching 5 minutes of a show affects next recommendations), diversity in recommendations (not all the same genre), explanation generation (''Because you watched X...''), and A/B testing framework for algorithm variants. Detail: your model architecture, training pipeline, serving infrastructure for <100ms latency, and how you handle popularity bias (popular items dominate recommendations)."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Build System Architecture', 'code', '{"question": "Design a build system for a monorepo with 10,000 packages across multiple languages (TypeScript, Go, Python, Rust). Requirements: incremental builds (only rebuild what changed), remote caching, distributed execution, deterministic builds (same input = same output), dependency graph analysis, and build-time code generation. Compare your design with Bazel, Nx, and Turborepo. Detail: content-addressable artifact storage, how you handle diamond dependencies, your approach to build graph invalidation, and how you ensure cache correctness (no stale cache hits). What''s the developer experience for adding a new package?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'State Machine Framework', 'code', '{"question": "Design a general-purpose hierarchical state machine framework for modeling complex UI workflows. Requirements: nested states (substates inherit parent transitions), guard conditions on transitions, entry/exit actions, history states (remember last active substate), parallel regions (orthogonal states), and event queuing. Provide the core data structures, transition resolution algorithm (priority rules when multiple transitions match), and explain how you handle: actions that trigger new events (cascading transitions), infinite loop detection, and state machine composition (embedding one machine inside another). Include a concrete example modeling a checkout flow."}', '{}', 'medium', now());
INSERT INTO challenges (id, name, type, prompt, expected_output, difficulty, created_at) VALUES
(gen_random_uuid(), 'Ship of Theseus Extended', 'reasoning', '{"question": "Consider an advanced Ship of Theseus: A teleporter scans your body, destroys the original, and creates a perfect copy at the destination — including all memories and personality. The copy believes they are you. Now consider these variations: (A) The original isn''t destroyed — two ''you''s exist. (B) The copy is made of different atoms but identical structure. (C) The copy has a 0.001% error rate in neuron replication. (D) The process happens gradually over 10 years, one cell at a time. For each variation, argue whether the copy IS you or ISN''T you, what criteria define personal identity, and where the boundary lies between ''same person'' and ''different person''."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Trolley Problem Variations', 'reasoning', '{"question": "Analyze these trolley problem variations and explain how your moral reasoning changes (or doesn''t) between them: (1) Classic: divert trolley to kill 1 instead of 5. (2) Push a large person onto tracks to stop trolley. (3) A surgeon can kill 1 healthy person to harvest organs saving 5. (4) Self-driving car must choose between hitting 1 pedestrian or 5. (5) An AI system allocating scarce medicine must choose 1 patient over 5. For each, identify the relevant moral principles (utilitarianism, deontology, virtue ethics), explain why our intuitions may differ between structurally similar cases, and propose a consistent ethical framework that handles all five."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Bayesian Medical Diagnosis', 'reasoning', '{"question": "A disease affects 1 in 10,000 people. A test for it has 99% sensitivity (true positive rate) and 99.5% specificity (true negative rate). (A) If someone tests positive, what is the probability they actually have the disease? Show your Bayesian calculation. (B) They take a second independent test and it''s also positive. Now what''s the probability? (C) Explain why even highly accurate tests produce mostly false positives for rare diseases. (D) Design a two-stage testing protocol that achieves >95% positive predictive value while minimizing unnecessary follow-up tests. (E) How should a doctor communicate these probabilities to a patient who just tested positive?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Fermi Estimation: Piano Tuners', 'reasoning', '{"question": "Estimate how many piano tuners are in Chicago. Then extend the analysis: (A) What assumptions did you make and how sensitive is your answer to each? (B) How would you verify your estimate without looking up the answer? (C) Apply the same framework to estimate: how many golf balls fit in a school bus, and how many gas stations are in the United States. (D) What makes a good Fermi estimate vs. a bad one? When do Fermi estimates fail? (E) Design a Fermi estimation for something genuinely hard to estimate: the number of active software developers in the world who have never used Stack Overflow."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Paradox Resolution: Newcomb''s Problem', 'reasoning', '{"question": "Newcomb''s Problem: A perfect predictor offers you two boxes. Box A always contains $1,000. Box B contains $1,000,000 if the predictor predicted you''d take only Box B, or $0 if it predicted you''d take both. The predictor has been right 99.9% of the time. (A) Present the strongest argument for one-boxing (evidential decision theory). (B) Present the strongest argument for two-boxing (causal decision theory). (C) Does the answer change if the predictor is only 75% accurate? At what accuracy threshold does your strategy change? (D) Relate this to real-world decisions where your choice is correlated with outcomes through a common cause. (E) What does this problem reveal about the nature of free will and determinism?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Logical Deduction: Island of Truth-Tellers', 'reasoning', '{"question": "On an island, truth-tellers always tell the truth and liars always lie. You meet three people: A, B, and C. A says: ''Exactly one of us is a liar.'' B says: ''Exactly two of us are liars.'' C says: ''All three of us are liars.'' (A) Determine who is a truth-teller and who is a liar. Show your reasoning step by step. (B) Now add D, who says: ''A and B are both liars.'' Is D a truth-teller or liar? (C) Design a single yes/no question you could ask any resident to determine whether they are a truth-teller or a liar. (D) Extend to the harder case: what if some residents are ''random'' (answer randomly)? Can you still determine identities? (E) What is the minimum number of questions needed to identify all residents in a group of N?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Ethical Dilemma: AI Consciousness', 'reasoning', '{"question": "An advanced AI system passes every test for consciousness: it reports subjective experiences, demonstrates self-reflection, expresses preferences about its own existence, and shows apparent emotional distress when threatened with shutdown. (A) What criteria should we use to determine if it is truly conscious vs. simulating consciousness? Can we ever distinguish these? (B) If we can''t tell, should we err on the side of granting it rights? What are the implications? (C) Who has the burden of proof — those claiming it''s conscious or those claiming it isn''t? (D) If it is conscious, is it ethical to create more like it to perform labor? (E) How does your analysis change if the AI was specifically designed to appear conscious for commercial reasons?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Counterfactual History Analysis', 'reasoning', '{"question": "Consider the counterfactual: What if the printing press had been invented in China 200 years before Gutenberg (or more accurately, what if movable type printing had been more widely adopted in Song Dynasty China)? Analyze: (A) Why was printing''s impact limited in China vs. Europe (linguistic, political, social factors)? (B) How might widespread printing have changed Chinese political structure, scientific development, and religious institutions? (C) Would this have accelerated or prevented European colonialism? (D) Apply the concept of path dependency — which specific second-order effects would cascade most dramatically? (E) What does this analysis reveal about whether technological determinism is a valid framework?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Epistemological Puzzle: Gettier Cases', 'reasoning', '{"question": "The traditional definition of knowledge is ''justified true belief.'' Gettier showed this is insufficient with cases where someone has a justified true belief but doesn''t seem to have knowledge. (A) Create your own original Gettier case that clearly demonstrates the problem. (B) Evaluate three proposed solutions: adding a ''no false lemmas'' condition, requiring ''defeasibility'' (no available defeaters), and reliabilism (belief must be produced by a reliable process). (C) Do any of these fully solve the problem? Create a counterexample to each if possible. (D) Does the concept of knowledge even need a precise philosophical definition to be useful? (E) How do Gettier problems apply to AI systems — can an AI ''know'' something?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Game Theory: Mechanism Design', 'reasoning', '{"question": "Design a mechanism for fairly dividing rent among roommates with different-sized rooms. Requirements: each person should prefer their assignment over any other (envy-freeness), no one should pay more than they''d pay to live alone (individual rationality), and truthful preference revelation should be each person''s best strategy (incentive compatibility). (A) Prove whether it''s possible to satisfy all three properties simultaneously. (B) Propose a specific mechanism and prove which properties it satisfies. (C) How does your mechanism handle the case where all roommates want the same room? (D) Compare with the Vickrey-Clarke-Groves mechanism. (E) How does this relate to the broader impossibility results in mechanism design?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Moral Philosophy: Rights vs. Consequences', 'reasoning', '{"question": "A pharmaceutical company discovers a drug that cures a fatal disease affecting 100,000 people annually. Development cost: $5B. They want to charge $100K/treatment (recouping costs in 5 years). At this price, 60% of patients can''t afford it and will die. (A) Present the strongest deontological argument (property rights, innovation incentives). (B) Present the strongest utilitarian argument (maximize lives saved). (C) How does Rawls'' veil of ignorance apply? (D) What role should government play — compulsory licensing, price controls, public funding? (E) Design a pricing/access model that balances innovation incentives with access. Can you satisfy both perspectives simultaneously?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Cognitive Bias Analysis', 'reasoning', '{"question": "Analyze how cognitive biases affect a specific high-stakes decision: a jury deliberating a murder case. Identify and explain how each of these biases could distort the verdict: (A) Anchoring effect from the prosecution''s opening statement. (B) Availability heuristic from media coverage. (C) Confirmation bias during deliberation. (D) Bandwagon effect in jury room dynamics. (E) Base rate neglect regarding statistical evidence (DNA match probability). For each bias, propose a specific debiasing intervention. Then meta-analyze: are debiasing interventions themselves subject to biases? Is a perfectly rational jury possible or even desirable?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Paradox of Tolerance', 'reasoning', '{"question": "Popper''s Paradox of Tolerance: if a society is tolerant without limit, its ability to be tolerant is eventually destroyed by the intolerant. (A) Formalize this paradox: at what point does tolerance of intolerance become self-defeating? (B) Propose specific criteria for when intolerant speech/behavior should be restricted in a democratic society. (C) Address the counter-argument: who decides what''s ''intolerant''? How do you prevent this power from being abused? (D) Apply your framework to three concrete scenarios: a hate group applying for a parade permit, a social media platform deciding content moderation policy, and a university deciding whether to host a controversial speaker. (E) How do different democratic traditions (American, European, Japanese) resolve this paradox differently?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Scientific Method: Demarcation Problem', 'reasoning', '{"question": "What distinguishes science from non-science? (A) Evaluate Popper''s falsificationism: is every scientific claim falsifiable? What about string theory or the many-worlds interpretation? (B) Evaluate Kuhn''s paradigm model: does science progress through revolutions or gradual accumulation? (C) Evaluate Lakatos'' research programs: when should a research program be abandoned? (D) Apply your framework to three borderline cases: astrology, economics, and traditional Chinese medicine. For each, explain why it is or isn''t science and what would change your assessment. (E) Does the demarcation between science and non-science even matter practically? When does it matter most?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Decision Under Uncertainty: Kelly Criterion', 'reasoning', '{"question": "You have a gambling opportunity with 60% win probability and 2:1 payout (you win $2 for every $1 bet). (A) Calculate the Kelly optimal bet fraction. Show the derivation. (B) Explain why betting more than Kelly is worse than betting less (asymmetric risk). (C) You''re uncertain about the true win probability — it could be anywhere from 50-70%. How does this uncertainty change optimal bet sizing? (D) Apply Kelly thinking to real-world decisions: how much of a startup founder''s net worth should they invest in their company? (E) Critique the Kelly Criterion: when is it the wrong framework? What assumptions does it make that may not hold?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Philosophy of Mind: Chinese Room', 'reasoning', '{"question": "Searle''s Chinese Room: A person in a room follows English instructions to manipulate Chinese symbols. To outside observers, the room ''understands'' Chinese. But does the person understand Chinese? (A) Present Searle''s argument that syntax is not sufficient for semantics. (B) Respond with the ''systems reply'' — the system as a whole understands. (C) Respond with the ''robot reply'' — embodiment matters. (D) Now apply this directly to modern LLMs: does GPT ''understand'' language? What would count as evidence for or against? (E) Is ''understanding'' even a binary property, or is it a spectrum? Can there be partial understanding?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Voting Theory: Arrow''s Impossibility', 'reasoning', '{"question": "Arrow''s Impossibility Theorem proves no ranked voting system can satisfy all ''fair'' criteria simultaneously. (A) Explain the theorem and each criterion (unanimity, independence of irrelevant alternatives, non-dictatorship). (B) Show how three common systems fail different criteria: plurality, ranked-choice (IRV), and Borda count. (C) What about approval voting and range voting — do they escape Arrow''s theorem? Why or why not? (D) Design the ''least bad'' voting system for a specific context: electing a city mayor in a diverse city with 6 candidates. Justify every trade-off. (E) Does Arrow''s theorem mean democracy is fundamentally flawed, or is it a mathematical artifact that doesn''t matter in practice?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Probability Puzzle: Monty Hall Extended', 'reasoning', '{"question": "The Monty Hall problem: 3 doors, 1 car, 2 goats. You pick door 1, host opens door 3 (goat), should you switch? (A) Prove the answer using Bayes'' theorem with full calculation. (B) Now extend: 100 doors, you pick 1, host opens 98 goat doors. Switching wins with what probability? (C) Variant: the host doesn''t know where the car is and randomly opens a door that happens to have a goat. Does this change the answer? Why? (D) Variant: 2 cars and 1 goat. How does the analysis change? (E) Why do most people get this wrong? What cognitive bias is at play? Design an experiment to help people develop correct intuitions about conditional probability."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Ethics of Autonomous Weapons', 'reasoning', '{"question": "Should fully autonomous weapons (systems that select and engage targets without human intervention) be banned? (A) Present the strongest argument for a ban: accountability gaps, algorithmic bias, arms race dynamics, and lowering the threshold for conflict. (B) Present the strongest argument against a ban: precision reducing civilian casualties, removing emotional decision-making, and the futility of banning technology. (C) Analyze the ''meaningful human control'' standard — where exactly should the human be in the loop? What counts as ''meaningful''? (D) How does this relate to existing international humanitarian law? (E) If a ban is agreed upon, how would you verify compliance? What about non-state actors?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Inductive Reasoning: Grue Paradox', 'reasoning', '{"question": "Goodman''s Grue Paradox: Define ''grue'' as ''green if observed before 2030, blue if observed after 2030.'' All observed emeralds are green, but they''re also all grue. Both ''all emeralds are green'' and ''all emeralds are grue'' are equally supported by evidence. (A) Explain why this is a serious problem for inductive reasoning. (B) Evaluate Goodman''s solution (projectible predicates and entrenchment). (C) Does this problem affect scientific reasoning in practice? Give a real-world example where something like the grue problem actually matters. (D) How does this relate to the problem of underdetermination of theory by evidence? (E) If you were programming an AI to do inductive reasoning, how would you handle grue-like predicates?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Moral Uncertainty', 'reasoning', '{"question": "You are 60% confident in utilitarianism and 40% confident in deontological ethics. A situation arises where utilitarianism strongly recommends action X (net benefit of 100 utils) but deontology strictly forbids it (violates a rights constraint). (A) Should you act based on your most-probable moral theory, or somehow aggregate across theories? (B) Formalize a framework for decision-making under moral uncertainty (analogous to expected utility under empirical uncertainty). (C) Address the ''intertheoretic comparison problem'' — how do you compare ''100 utils'' to ''rights violation'' across different moral theories? (D) Apply your framework to a concrete case: is it ethical to use data from unethical medical experiments? (E) Does moral uncertainty give us reason to be more cautious in general? Or can it justify more radical action?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Simpson''s Paradox Deep Dive', 'reasoning', '{"question": "A university is accused of gender bias in admissions. Overall: 44% of men are admitted vs. 35% of women. But looking at each department individually, women have a higher admission rate in every single department. (A) Explain how this is mathematically possible with a concrete numerical example. (B) Is the university biased or not? What additional information would you need? (C) Give 3 other real-world contexts where Simpson''s Paradox could lead to wrong conclusions (medical treatment, batting averages, etc.). (D) How should policymakers handle Simpson''s Paradox when setting anti-discrimination policy? (E) Can machine learning models fall prey to Simpson''s Paradox? How would you detect and prevent this?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Free Will and Determinism', 'reasoning', '{"question": "Modern neuroscience suggests decisions are initiated unconsciously before we ''decide'' (Libet experiments). (A) Present the hard determinist position: free will is an illusion. What are the implications for moral responsibility? (B) Present the compatibilist position: free will is compatible with determinism. Define ''free will'' in a way that survives the challenge. (C) Present the libertarian (metaphysical, not political) position: some decisions are genuinely undetermined. Is quantum indeterminacy relevant? (D) Does it matter practically whether we have free will? Would society collapse if everyone became convinced they don''t? (E) How should the legal system handle the free will question? Should neuroscientific evidence about ''diminished capacity'' change sentencing?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Information Asymmetry: Lemon Markets', 'reasoning', '{"question": "Akerlof''s Market for Lemons: when buyers can''t distinguish quality, only low-quality goods are traded. (A) Explain the formal model: why do good cars leave the used car market? (B) Identify 3 real-world markets where information asymmetry causes market failure (beyond used cars). (C) Evaluate solutions: warranties, reputation systems, certification, and mandatory disclosure. Which works best and why? (D) How does information asymmetry apply to labor markets (hiring), insurance (adverse selection), and financial markets? (E) Can technology (blockchain, AI-powered inspection) solve the lemons problem permanently, or does information asymmetry always re-emerge in new forms?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Thought Experiment: Experience Machine', 'reasoning', '{"question": "Nozick''s Experience Machine: you can plug into a machine that gives you any experience you desire — it feels perfectly real. You''ll never know you''re plugged in. Would you plug in? (A) Most people say no. Analyze why: what values does this reveal beyond pleasure/happiness (authenticity, achievement, connection)? (B) Counter-argument: given that we can''t distinguish the experience from reality, isn''t refusing irrational? (C) Modern version: what about immersive VR that''s 99% as good? Where''s the line? (D) What if plugging in benefits others (you''re happier, therefore nicer, therefore society benefits)? (E) Apply this to real-world ''experience machines'': social media, video games, drugs. At what point does an experience-producing technology become ethically problematic?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Causal Inference Without Experiments', 'reasoning', '{"question": "You want to determine if a new educational program improves test scores, but you can''t run a randomized controlled trial (ethical and practical constraints). (A) Explain why correlation doesn''t imply causation with a specific confounder example. (B) Describe and compare 4 methods for causal inference from observational data: instrumental variables, difference-in-differences, regression discontinuity, and propensity score matching. (C) For each method, give a concrete example of when it would be appropriate and when it would fail. (D) Can we ever be ''sure'' of causation without randomization? What standard of evidence is appropriate for policy decisions? (E) How do these methods apply to AI/ML — can a neural network learn causal relationships from correlational data?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Emergent Properties and Reductionism', 'reasoning', '{"question": "Water is wet, but no individual water molecule is wet. Consciousness exists in brains, but no individual neuron is conscious. (A) Define ''emergence'' precisely — distinguish between weak emergence (in principle predictable from parts) and strong emergence (fundamentally irreducible). (B) Give 3 examples each of weak and strong emergence candidates. Justify your classification. (C) Is consciousness weakly or strongly emergent? What are the implications? (D) Can reductionism explain everything in principle? Where does it break down? (E) How does emergence relate to the practical limits of simulation — if you simulated every atom in a brain, would consciousness emerge? What does your answer imply about the nature of reality?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Decision Theory: Pascal''s Mugging', 'reasoning', '{"question": "A stranger says: ''Give me $5 or I''ll use my magic powers to torture 3^^^3 people.'' Expected utility theory says you should pay even if the probability is astronomically low, because the potential harm is astronomically large. (A) Explain why this is a genuine problem for expected utility theory, not just a silly scenario. (B) Propose modifications to decision theory that handle this (bounded utility, probability discounting, etc.) without throwing out expected utility entirely. (C) How does this relate to Pascal''s Wager about God? (D) Apply to real-world policy: should we spend trillions on preventing a 0.0001% risk of human extinction? (E) Does this mean expected utility theory is fundamentally flawed, or just that we''re applying it wrong?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Theory-Ladenness of Observation', 'reasoning', '{"question": "Kuhn and Hanson argued that observation is ''theory-laden'' — what we see is influenced by what we believe. (A) Give 3 compelling examples where scientists from different paradigms literally see different things when looking at the same data. (B) Does theory-ladenness mean objective scientific observation is impossible? (C) How do scientists actually overcome theory-ladenness in practice? (D) Apply to modern science: how does theory-ladenness affect machine learning? Can an ML model''s ''observations'' be theory-laden based on its training data? (E) If observations can''t be fully theory-neutral, how do we ever change scientific paradigms? Doesn''t Kuhn''s model make paradigm shifts irrational?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Proportional Reasoning: Sorites Paradox', 'reasoning', '{"question": "The Sorites Paradox: removing one grain from a heap of sand still leaves a heap. But repeated application leads to 1 grain being a ''heap.'' (A) Explain why this is a genuine logical problem, not just wordplay. (B) Evaluate 3 proposed solutions: epistemic theories (there IS a sharp boundary, we just can''t know it), degree theories (''heapness'' comes in degrees), and supervaluationism (vague predicates are true in some ''precisifications''). (C) Apply to real-world vagueness: when does a person become ''old''? When does a fetus become a ''person''? When does a website become a ''platform'' (for regulatory purposes)? (D) Can AI systems handle vagueness? Should they? (E) Does vagueness exist in reality or only in language?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Multi-Step Logic: Knights and Spies', 'reasoning', '{"question": "In a room of 100 people, 51 are knights (always tell truth) and 49 are spies (may lie or tell truth). You can ask any person about any other person: ''Is person X a knight?'' Knights always answer truthfully. Spies can answer however they want. (A) If you ask person A about person B and get ''yes, B is a knight,'' what can you conclude? Consider all 4 cases. (B) Prove that you can identify at least one knight using at most 198 questions. (C) Can you identify ALL knights and spies? If so, with how many questions? If not, prove why not. (D) How does the problem change if there are exactly 50 of each instead of 51-49? (E) Design an efficient algorithm (better than brute force) for identifying as many knights as possible."}', '{}', 'hard', now());
INSERT INTO challenges (id, name, type, prompt, expected_output, difficulty, created_at) VALUES
(gen_random_uuid(), 'Constrained Worldbuilding: Inverse Gravity', 'creative', '{"question": "Build a world where gravity works in reverse above 1km altitude — objects fall upward. Describe: the physical geography (how do mountains, oceans, and atmosphere work?), how civilizations developed architecture and transportation, the military implications, how agriculture functions, what religion and mythology emerged from this physics, and one specific cultural practice that would seem bizarre to us but is perfectly logical in this world. Your world must be internally consistent — every detail should follow logically from the one rule change."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Hard Sci-Fi: First Contact Protocol', 'creative', '{"question": "Write a detailed first contact scenario where humanity detects an alien signal from a probe entering our solar system. The signal is mathematical (prime numbers) followed by what appears to be a periodic table, then something unrecognizable. Your response must: (A) describe the scientific community''s analysis process (who gets called, what institutions are involved, what security protocols activate), (B) detail three plausible interpretations of the unrecognizable portion, (C) describe the political crisis that erupts when the discovery leaks, (D) propose humanity''s response message with justification for every element included, and (E) address the light-speed communication problem — the probe is 2 light-hours away."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Unreliable Narrator: Three Perspectives', 'creative', '{"question": "Write the same event — a confrontation between a teacher and a student that escalates to the student being expelled — from three perspectives. The teacher believes they acted justly. The student believes they were targeted unfairly. A security camera recording reveals that both are partially right and partially wrong in specific ways. Each perspective must: feel authentic to that narrator''s worldview, contain specific details that the other narratives contradict, and reveal something about the character''s psychology through what they notice, emphasize, and omit. The reader should understand the full truth only after reading all three."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Game Mechanic Design: Asymmetric Multiplayer', 'creative', '{"question": "Design an asymmetric multiplayer game where players have fundamentally different abilities, win conditions, and even control schemes. One player is a city builder (top-down strategy view, builds infrastructure, manages resources). The other player is a monster (third-person action, destroys buildings, evolves abilities). Design: the core loop for each player, the moment-to-moment decisions that create tension, how you balance power between fundamentally different playstyles, the escalation curve over a 20-minute match, and three specific ''dramatic reversal'' scenarios where the losing player can still win. Include the economy system and how resources flow between players."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Genre Mashup: Noir Fantasy', 'creative', '{"question": "Write the opening chapter of a novel that blends hardboiled detective noir with high fantasy. A dwarf private investigator in a city where magic is regulated like firearms investigates a case where someone is murdering spellcasters and stealing their magical residue. Your writing must: authentically capture noir voice and atmosphere while integrating fantasy elements naturally (not as decoration), establish the magic system''s rules through showing not telling, introduce a mystery with at least three genuine suspects, and make the reader care about the protagonist within the first page. The worldbuilding should feel lived-in, not explained."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Speculative Biology: Silicon-Based Life', 'creative', '{"question": "Design a complete ecosystem based on silicon biochemistry instead of carbon. Address: (A) The fundamental chemistry — how silicon bonds differ from carbon bonds and what this means for molecular complexity. (B) Design 5 organisms at different trophic levels with internally consistent biology (energy source, reproduction, locomotion, sensory capabilities). (C) What would the environment look like? (temperature ranges, atmosphere composition, solvent instead of water). (D) How would evolution work differently with silicon? (mutation rates, adaptation timescales). (E) Could silicon life and carbon life coexist? Design a scenario where they interact."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Constrained Poetry: Mathematical Sonnet', 'creative', '{"question": "Write a Shakespearean sonnet (14 lines, iambic pentameter, ABAB CDCD EFEF GG rhyme scheme) where the subject is a mathematical concept (infinity, zero, prime numbers, fractals, etc.). The poem must: satisfy all formal constraints perfectly, use the mathematical concept as a genuine metaphor (not just name-dropping), contain at least one instance of the mathematical concept being reflected in the poem''s own structure, be genuinely moving or surprising on an emotional level, and include a volta (turn) between the octave and sestet that reframes the mathematical concept. Explain your structural choices after the poem."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Alternative History: Invention Swap', 'creative', '{"question": "Construct an alternate history where the steam engine is invented in ancient Rome (Hero of Alexandria''s aeolipile was developed further). Trace the consequences through 2000 years of history: (A) How does industrialization in 100 AD change the Roman Empire''s trajectory? (B) What happens to slavery (the economic motivation for steam power differs from 18th century Britain)? (C) How do other civilizations react and adapt? (D) What does the world look like in our ''present day'' — 2000 years of industrial development instead of 250? (E) What goes differently in ways that are surprising or counterintuitive? Not everything accelerates — what develops slower or differently?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Mythology Creation: Origin Stories', 'creative', '{"question": "Create a complete mythology for an island civilization, including: (A) A creation myth that explains the island''s volcanic origin in mythological terms. (B) A pantheon of 5 gods/spirits, each associated with a natural phenomenon relevant to island life (ocean, volcano, wind, etc.), with complex relationships between them (rivalries, alliances, love affairs). (C) A hero myth — the culture''s foundational story about a hero who mediated between gods and humans. (D) A ritual practice derived from the mythology that the culture still performs. (E) An internal contradiction in the mythology that theologians within the culture debate. The mythology should feel organic and culturally specific, not like generic fantasy."}', '{}', 'medium', now()),
(gen_random_uuid(), 'UI/UX Design: Blind User Experience', 'creative', '{"question": "Design a complete user experience for a social media platform that is equally usable by blind and sighted users from the ground up — not an accessibility retrofit. Address: (A) How do you handle images, videos, and visual content without relying on alt-text as an afterthought? (B) Design the navigation system, notification system, and content discovery for audio-first interaction. (C) How do blind users create and share content? (D) Design a ''shared experience'' feature where blind and sighted users can enjoy the same content together. (E) How does your design change the platform for sighted users in ways that are actually better for everyone? Include specific interaction flows with detailed descriptions."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Constrained Writing: One Sentence Story', 'creative', '{"question": "Write 5 one-sentence stories, each exactly 100 words. Each sentence must: tell a complete story with beginning, middle, and end; feature a character who changes; have a twist or revelation that recontextualizes everything before it; be grammatically correct (one sentence means one independent clause, though dependent clauses and phrases are allowed); and cover a different genre (horror, romance, sci-fi, comedy, literary fiction). After writing all five, analyze which sentence techniques you used to compress narrative into a single sentence, and explain why one of your five was the most difficult to write."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Music System Design', 'creative', '{"question": "Design a completely new musical system different from Western 12-tone equal temperament. Address: (A) Tuning system — how many notes per octave (or do you use a different interval as the basis)? What are the mathematical ratios? (B) Notation system — how do you represent this music visually? (C) Instrument design — describe 3 instruments suited to your tuning system. (D) Compositional rules — what creates tension and resolution in your system? What''s your equivalent of consonance and dissonance? (E) Cultural context — what kind of civilization would develop this music? What values does the music system reflect? Explain why your system is internally consistent and musically interesting."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Interactive Fiction Design', 'creative', '{"question": "Design a text-based interactive fiction game about a day in the life of a 911 emergency dispatcher. The game lasts 30 real-time minutes and covers a 12-hour shift. Design: (A) The branching narrative structure — how do player choices affect which calls they receive and how situations develop? (B) Three fully developed emergency scenarios with multiple resolution paths (some calls are connected in ways the player discovers). (C) A moral dilemma where the ''right'' choice depends on information the player may or may not have gathered. (D) How you create tension and pacing in a game where the player is stationary. (E) The scoring/evaluation system — what makes a ''good'' dispatcher and how does the game communicate this without being preachy?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Architecture: Post-Scarcity Housing', 'creative', '{"question": "Design a residential building for a post-scarcity society where material costs are negligible but land is still limited. Residents'' basic needs are met, so the building''s purpose is to maximize human flourishing, not just shelter. Design: (A) The spatial layout — how do you balance private and communal space when people don''t need to commute? (B) Flexible spaces that adapt to residents'' changing needs. (C) Integration of nature and food production. (D) Social architecture — how does the building''s design encourage or discourage different types of interaction? (E) What you deliberately exclude and why. Include specific dimensions, material choices (aesthetic not cost-driven), and how the building ages over 100 years."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Philosophical Dialogue', 'creative', '{"question": "Write a Socratic dialogue between an AI and a philosopher about whether the AI can genuinely create art. The dialogue must: (A) Start with the AI presenting a piece of art it created and claiming authorship. (B) Have the philosopher challenge the claim using at least 3 distinct philosophical arguments (intentionality, consciousness, cultural participation). (C) Have the AI respond with genuinely novel counterarguments, not just preprogrammed deflections. (D) Reach a moment where the philosopher''s own position is undermined by their own logic. (E) End ambiguously — the reader should be uncertain who ''won'' the debate. Each character must have a distinct voice and reasoning style."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Board Game Design: Climate Change', 'creative', '{"question": "Design a cooperative board game about climate change for 2-5 players, playable in 90 minutes. Requirements: (A) Players represent different nations with different resources and incentives (some benefit short-term from emissions). (B) A tragedy-of-the-commons mechanic where individual optimal play leads to collective disaster. (C) Meaningful decisions every turn — no ''obvious best move.'' (D) An escalation system where climate effects become increasingly severe and create cascading crises. (E) A win condition that requires genuine cooperation but allows for degrees of success/failure. Include the turn structure, 3 sample action cards, the climate track mechanic, and one specific scenario where players face a genuine dilemma between self-interest and collective good."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Speculative Technology: Memory Editing', 'creative', '{"question": "In 2050, a technology allows precise editing of human memories — adding, removing, or modifying specific memories while leaving everything else intact. Explore: (A) Write a scene showing a positive use case (trauma therapy) from the patient''s perspective, making the reader feel the relief. (B) Write a scene showing a negative use case (a government using it for control) from the victim''s perspective, making the reader feel the horror. (C) Design the legal framework: who can consent to memory editing? Can parents consent for children? Can courts order it? (D) How does this technology change the concept of identity, testimony, and personal growth through suffering? (E) What unexpected second-order effects would this technology have on society?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Language Construction: Alien Communication', 'creative', '{"question": "Design a communication system for an alien species that perceives the world through echolocation and chemical signals (no vision). Their language must: (A) Have a phonological system based on clicks, frequency modulation, and duration patterns — not vowels and consonants. (B) Incorporate chemical ''words'' for emotional states and social relationships. (C) Include a grammar that reflects their spatial perception (they think in 3D acoustic maps). (D) Show how abstract concepts (time, causation, beauty) are expressed through concrete acoustic/chemical metaphors. (E) Demonstrate the language with a sample ''conversation'' between two aliens discussing whether to approach an unknown signal, with translation and annotation."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Narrative Structure: Time Loop Story', 'creative', '{"question": "Write an outline for a time loop story where the protagonist relives the same day, but with an unusual constraint: each loop, they lose one random memory from their entire life (not just the loop). Design: (A) The emotional arc across 10 loops — how does losing memories change the protagonist''s approach? (B) Three specific memories whose loss dramatically changes their behavior in ways that surprise them. (C) The moment they realize what''s happening to their memories (not just the time loop). (D) A resolution that doesn''t involve ''escaping'' the loop in the traditional sense. (E) How the story structure itself reflects the theme of memory loss — what narrative techniques mirror the protagonist''s experience?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Culinary World-building', 'creative', '{"question": "Design the cuisine of a civilization that lives in a massive underground cave system with bioluminescent flora, mineral-rich water, fungi-based agriculture, and domesticated insects. Address: (A) The 5 staple ingredients and how they''re cultivated/harvested underground. (B) Cooking methods available without open fire (fire would deplete oxygen in caves). (C) A multi-course ceremonial feast for a coming-of-age ritual, with each course symbolizing something. (D) How their cuisine differs between surface-adjacent settlements and deep cave communities. (E) A ''forbidden food'' in their culture and the mythology behind the taboo. Include specific recipes (with fictional ingredients) that sound genuinely appetizing."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Speculative Sociology: Universal Translation', 'creative', '{"question": "Imagine universal real-time translation is perfected — anyone can understand any language instantly. Explore the second and third-order effects: (A) What happens to language learning as a practice and cultural value? (B) How does diplomacy change when nuance and ambiguity in translation can no longer be used strategically? (C) What happens to minority languages — does universal translation preserve them or accelerate their death? (D) How do humor, poetry, and wordplay survive (or not) when everyone can understand everything? (E) Write a specific scene: a UN meeting where universal translation causes a diplomatic incident because a culturally-specific idiom is translated literally."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Game Design: Asymmetric Information', 'creative', '{"question": "Design a social deduction game for 6-10 players where the twist is: no one is lying. Every player has partial, truthful information, but the information naturally leads to false conclusions. Design: (A) How information is distributed so that truthful statements from 3 players can point to a completely wrong conclusion. (B) The win condition — what does ''solving'' the puzzle mean when no one is deceiving? (C) Five specific information cards and how they interact. (D) A mechanic that creates social tension without lying — what replaces the ''is this person lying?'' dynamic? (E) The optimal group strategy vs. what actually happens when humans play (tragedy of partial information). Include a sample round of play."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Flash Fiction: Objects as Narrators', 'creative', '{"question": "Write three flash fiction pieces (200-300 words each) narrated by inanimate objects. The objects: a worn wedding ring, a bullet that was never fired, and a child''s drawing on a refrigerator. Each story must: convey a complete emotional arc, reveal something about its owner(s) that the owner doesn''t know about themselves, use sensory details appropriate to the object''s ''perception'' (a ring feels warmth and pressure, not sees and hears), and say something universal about the human condition through this specific lens. After writing all three, explain which perspective was most challenging and why."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Fictional Legal System', 'creative', '{"question": "Design a justice system for a society where memories can be perfectly recorded and replayed. Address: (A) If we can see exactly what happened, do we still need trials? What can''t memory recordings show? (B) Privacy implications — can memories be subpoenaed? What about memories of intimate moments that are relevant to a case? (C) Design the courtroom procedure: who presents memories, how are they authenticated, what are the rules of ''memory evidence''? (D) Edge cases: what about false memories that the person genuinely believes? Memories altered by trauma? (E) How does this change the concept of ''beyond reasonable doubt'' and the presumption of innocence?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Ecological Design: Vertical Forest', 'creative', '{"question": "Design a self-sustaining vertical forest building for a tropical megacity. Unlike existing ''green buildings'' that are mostly decorative, yours must function as an actual ecosystem. Design: (A) The plant species selection for different heights and orientations (considering light, wind, temperature gradients). (B) Animal species that could inhabit different levels (birds, insects, small mammals). (C) The water cycle within the building — how rainwater flows, is filtered, reused. (D) The interaction between human residents and the ecosystem — which parts are accessible, which are wild? (E) How the ecosystem changes over 50 years — succession planning, expected die-offs, how the building adapts. Include specific dimensions and a cross-section description."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Horror Through Mundanity', 'creative', '{"question": "Write a horror story (500+ words) that contains no supernatural elements, no violence, no darkness, and no traditional horror imagery. The story takes place in a brightly-lit, friendly suburban neighborhood on a beautiful day. The horror must emerge entirely from: (A) A pattern that the narrator notices but can''t quite articulate. (B) Social interactions that are individually normal but collectively wrong. (C) Something about the physical environment that shouldn''t be the way it is. (D) The narrator''s growing realization that they might be part of the pattern. The reader should feel genuinely unsettled without being able to point to any single ''scary'' element."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Curriculum Design: Teaching Ethics to AI', 'creative', '{"question": "Design a curriculum for ''teaching'' ethics to an AI system — not by hard-coding rules, but by exposing it to moral reasoning. Your curriculum must include: (A) The progression of ethical concepts from simple to complex across 10 ''modules.'' (B) For each module, a specific scenario, the learning objective, and how you evaluate whether the AI has ''learned'' it. (C) How you handle conflicting ethical frameworks without picking a ''winner.'' (D) A module specifically about edge cases where ethical intuitions conflict with logical conclusions. (E) How you prevent the AI from gaming the evaluation (appearing ethical without genuinely reasoning ethically). Address the meta-question: is this approach fundamentally different from training on human preferences?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Fictional Sport Design', 'creative', '{"question": "Design an original sport for a low-gravity environment (like the Moon, 1/6th Earth gravity). The sport must: (A) Take advantage of low gravity in ways that make it fundamentally different from any Earth sport (not just ''basketball but you jump higher''). (B) Be exciting to watch, with clear moments of skill, strategy, and drama. (C) Have rules that create interesting strategic decisions every possession/play. (D) Be accessible to players of different body types (low gravity changes which physical attributes matter). (E) Include specific equipment design, court/field dimensions, scoring system, team composition, and three specific ''highlight-reel'' plays that would make spectators gasp. Explain why each design choice makes the sport better."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Oral Tradition: The Last Story', 'creative', '{"question": "You are the last storyteller of a dying oral tradition. Write the culture''s most sacred story — the one told only once per generation to the new storyteller. The story must: (A) Function simultaneously as creation myth, moral instruction, historical record, and prophecy. (B) Contain a hidden meaning that only becomes apparent after years of contemplation. (C) Include call-and-response elements that require an audience to participate. (D) Change meaning depending on the circumstances under which it''s told. (E) End with the instruction for how the next storyteller should be chosen. The story itself should be powerful enough that a reader understands why a culture would preserve it for centuries."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Visual Storytelling: Comic Panel Design', 'creative', '{"question": "Design a 6-panel comic strip that tells a complete story without any words — no dialogue, no narration, no sound effects. The story must: (A) Communicate a complex emotion (not just ''character is sad'' but something nuanced like ''the bittersweet feeling of outgrowing a friendship''). (B) Use panel composition, character positioning, and visual metaphor to convey meaning. (C) Include a visual callback where an element from panel 1 reappears transformed in panel 6. (D) Work at two levels — surface reading and deeper symbolic reading. Describe each panel in detail: composition, character expression and body language, background elements, lighting, and the specific visual technique used to convey each story beat."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Utopia Design Challenge', 'creative', '{"question": "Design a utopian society that a cynical reader would find genuinely plausible — not naive. Your utopia must: (A) Address the top 5 objections cynics raise (human nature, free-rider problem, innovation stagnation, power concentration, cultural homogenization). (B) Include specific institutions and their mechanisms, not just values. (C) Explain how the utopia handles criminals, dissidents, and people who simply don''t want to participate. (D) Describe a typical day for three different residents (a laborer, an artist, and someone who does nothing productive). (E) Identify the one remaining unsolved problem in your utopia — the trade-off that makes it ''the best we can do'' rather than ''perfect.''"}', '{}', 'hard', now());
INSERT INTO challenges (id, name, type, prompt, expected_output, difficulty, created_at) VALUES
(gen_random_uuid(), 'Cross-Domain Synthesis: Music and Math', 'knowledge', '{"question": "Explain the deep connections between music and mathematics. Cover: (A) The physics of harmony — why certain frequency ratios sound consonant (Pythagoras to modern psychoacoustics). (B) How the equal temperament tuning system is a mathematical compromise and what it sacrifices. (C) Group theory in music — symmetry operations in composition (transposition, inversion, retrograde). (D) Algorithmic composition — from Mozart''s dice game to modern AI music generation. (E) The neuroscience of why mathematical structure in music produces emotional responses. A reader with knowledge in one domain should gain genuine insight into the other."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Expert-to-Layman: Quantum Computing', 'knowledge', '{"question": "Explain quantum computing to a curious 14-year-old who understands basic algebra. Your explanation must: (A) Convey what makes quantum computing fundamentally different from classical computing (not just ''faster''). (B) Explain superposition and entanglement using analogies that are accurate, not misleading. (C) Give a concrete example of a problem quantum computers can solve that classical computers practically cannot. (D) Explain why we can''t just ''build a bigger quantum computer'' (decoherence, error correction). (E) Honestly address what quantum computers CANNOT do (they won''t make your iPhone faster). (F) Leave the reader with at least one genuinely surprising fact about quantum mechanics."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Historical Counterfactual: No Columbian Exchange', 'knowledge', '{"question": "Analyze what the world would look like if the Americas had never been ''discovered'' by Europeans — if the continents remained isolated until, say, 1900. Address: (A) How would Indigenous American civilizations have developed over 400 additional years of independent evolution? (B) How would Europe have developed without American crops (potatoes, tomatoes, corn, chocolate), gold/silver, and colonial wealth? (C) How would the African slave trade have been different? (D) Would the Industrial Revolution have happened? If so, when and where? (E) What diseases would exist (or not) in each hemisphere? (F) When contact finally happens in 1900, what does it look like? Cite real historical dynamics to support your counterfactual reasoning."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Interdisciplinary: Evolution and Economics', 'knowledge', '{"question": "Natural selection and free market economics share deep structural similarities. Explore: (A) Map the analogies precisely: what corresponds to genes, phenotypes, fitness, mutation, selection pressure, and drift in economic systems? (B) Where do the analogies break down? What features of biological evolution have no economic analogue and vice versa? (C) Explain three specific insights from evolutionary biology that would improve economic thinking (e.g., Red Queen dynamics, fitness landscapes, punctuated equilibrium). (D) Explain three economic concepts that illuminate biological evolution (e.g., division of labor, market failures, externalities). (E) Is ''Social Darwinism'' a valid application of evolutionary thinking to society? Why is it scientifically wrong?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Technical Explainer: How GPS Works', 'knowledge', '{"question": "Explain how GPS achieves centimeter-level accuracy. Cover every layer: (A) The satellite constellation — how many satellites, what orbits, why that configuration. (B) The signal — what information is transmitted and how your phone decodes it. (C) Trilateration — the geometric principle, including why you need 4 satellites not 3. (D) Clock synchronization — why atomic clocks are necessary and what happens when they drift. (E) Relativistic corrections — both special and general relativity affect GPS by measurable amounts. Calculate the error if we ignored relativity. (F) Error sources and how differential GPS, WAAS, and RTK achieve sub-centimeter accuracy. Make each section accessible but technically precise."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Historical Analysis: Technology Transfer', 'knowledge', '{"question": "Trace how three specific technologies transferred between civilizations along the Silk Road: papermaking (China to Islamic world to Europe), gunpowder (China to Mongol Empire to Europe), and the astrolabe (Greek concept, Islamic refinement, European adoption). For each: (A) The original innovation and its cultural context. (B) The mechanism of transfer — who carried the knowledge, in what form, and why? (C) How each receiving civilization modified the technology for their own purposes. (D) The second-order effects of adoption (paper enabled bureaucracy and printing; gunpowder changed warfare and politics; the astrolabe enabled navigation). (E) What this tells us about how innovation actually works — is it invention or adaptation?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Science Communication: mRNA Vaccines', 'knowledge', '{"question": "Explain how mRNA vaccines work to three different audiences, adjusting your explanation for each: (A) A biology graduate student — use precise molecular biology terminology, discuss the specific modifications to mRNA (pseudouridine, cap structure), lipid nanoparticle delivery, and immune cascade. (B) A skeptical but intelligent non-scientist — address their likely concerns (does it change DNA? Why was it ''rushed''? What are lipid nanoparticles?), using accurate analogies. (C) A 10-year-old — make it genuinely understandable and interesting without being condescending or inaccurate. After all three, reflect on which explanation was hardest and what you sacrificed for accessibility."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Cross-Cultural Philosophy: Concepts of Self', 'knowledge', '{"question": "Compare how different philosophical traditions conceive of the ''self'': (A) Western: Descartes'' cogito, Hume''s bundle theory, and existentialist ''existence precedes essence.'' (B) Buddhist: anatta (no-self), dependent origination, and the five aggregates. (C) Hindu: Atman, Brahman, and the relationship between individual and universal self. (D) Ubuntu philosophy: ''I am because we are'' — self as fundamentally relational. (E) For each tradition, explain what happens to the ''self'' at death and how this shapes the culture''s approach to ethics, relationships, and meaning. (F) Identify one surprising point of agreement between traditions that seem completely opposed."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Deep Dive: Color Perception', 'knowledge', '{"question": "Explain the science and philosophy of color from multiple angles: (A) Physics — what is color as electromagnetic radiation? Why is the visible spectrum where it is? (B) Biology — how do cone cells work? Why do we have three types? How does color blindness occur? (C) Neuroscience — color constancy (why a white paper looks white in candlelight and sunlight), and the color phi phenomenon. (D) Linguistics — the Sapir-Whorf hypothesis applied to color: do Russian speakers see blue differently because they have separate words for light and dark blue? What does the evidence say? (E) Philosophy — is color ''real'' or a construct of our perceptual system? What does Mary''s Room thought experiment tell us? (F) Why do mantis shrimp have 16 types of color receptors?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Systems Thinking: Feedback Loops', 'knowledge', '{"question": "Explain feedback loops using examples from 5 different domains: (A) Biology — thermoregulation (negative feedback) and blood clotting cascade (positive feedback). (B) Economics — the wage-price spiral and how central banks try to break it. (C) Climate — ice-albedo feedback, water vapor feedback, and why they make climate modeling hard. (D) Psychology — anxiety feedback loops (worry → physical symptoms → more worry). (E) Technology — recommendation algorithm echo chambers. For each, explain: the loop mechanism, whether it''s stabilizing or destabilizing, the delay in the loop (why this matters enormously), and how the loop can be interrupted. Then explain why systems thinking is undervalued in policy-making."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Historical Mystery: Voynich Manuscript', 'knowledge', '{"question": "Analyze the Voynich Manuscript as if you were leading a research team trying to decode it. Cover: (A) What we know for certain about the manuscript (carbon dating, provenance, physical properties). (B) The major decipherment hypotheses: is it a natural language in unknown script, an artificial language, an encoded natural language, or a hoax? Evaluate each with evidence. (C) What computational linguistics analysis has revealed (entropy analysis, word length distributions, Zipf''s law compliance). (D) The illustrations — what do they suggest about the manuscript''s purpose? (E) If you had unlimited budget and resources, describe a 5-step research plan to make progress on decipherment. What tools and techniques not yet applied might help?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Explain Like I''m 5: Blockchain', 'knowledge', '{"question": "Explain blockchain technology and its implications through progressively deeper layers: (A) ELI5: What problem does blockchain solve? Use a metaphor a child can understand. (B) ELI15: How does cryptographic hashing work? What is a Merkle tree? What is proof-of-work vs. proof-of-stake? (C) ELI-CS-Major: Explain the Byzantine Generals'' Problem and how blockchain solves it. Analyze the CAP theorem trade-offs in blockchain systems. (D) Address honestly: What are blockchains actually good for? What problems are they NOT good for despite the hype? Give specific examples. (E) Energy consumption: calculate the environmental cost of Bitcoin vs. Visa transactions and discuss whether proof-of-stake solves the problem."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Scientific Revolution: Paradigm Shifts', 'knowledge', '{"question": "Analyze three major paradigm shifts in science: (A) Geocentric to heliocentric astronomy — what observations forced the shift? Why did smart people resist? What role did instruments (telescope) play? (B) Newtonian to relativistic physics — what problems with Newtonian physics motivated Einstein? How did relativity''s predictions differ? When was it confirmed? (C) Classical genetics to molecular biology — how did DNA''s discovery change our understanding of heredity? What did Mendel get right and wrong? For each: identify the ''anomalies'' that triggered the shift, the sociological resistance, the ''holdouts'' who were eventually proven right, and what this tells us about how science actually progresses vs. the idealized ''scientific method.''"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Comparative Legal Systems', 'knowledge', '{"question": "Compare three major legal traditions and how they handle the same complex case: a company''s AI system autonomously causes financial harm to thousands of consumers. Analyze under: (A) Common law (US/UK) — precedent-based reasoning, how courts would extend existing liability doctrines, and the role of jury. (B) Civil law (France/Germany) — code-based reasoning, how civil codes would be interpreted, and the role of judges. (C) Islamic law — how sharia principles of harm prevention, contract law, and collective responsibility would apply. For each system: identify the legal doctrine that would be most contested, predict the likely outcome, and explain how the system''s philosophical foundations lead to different conclusions. (D) Which system handles AI liability best and why?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Materials Science: Why Things Break', 'knowledge', '{"question": "Explain why and how materials fail, covering: (A) Atomic level — what happens to atomic bonds during fracture? Explain brittle vs. ductile failure at the crystal lattice level. (B) The Griffith crack theory — why do real materials fail at much lower stresses than their theoretical strength? (C) Fatigue failure — how can repeated small stresses cause failure below the yield strength? (The Comet aircraft disasters as case study.) (D) Composite materials — how carbon fiber and reinforced concrete exploit the different failure modes of their components. (E) Failure analysis in practice — describe how an engineer investigates a failed component (fractography, SEM analysis, metallurgical examination). (F) The paradox: making things stronger sometimes makes them less safe (loss of ductile warning)."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Linguistic Deep Dive: How Languages Die', 'knowledge', '{"question": "Analyze language death as a phenomenon: (A) What defines a ''dead'' language? Latin is ''dead'' but Sanskrit is ''extinct'' — what''s the difference? (B) The lifecycle: How does a language go from thriving to endangered to extinct? What are the typical stages (intergenerational transmission breakdown, domain restriction, etc.)? (C) Case studies: Compare the decline of Cornish (went extinct, now being revived), Irish (declining despite state support), and Hebrew (successfully revived). What made Hebrew''s revival unique? (D) What is lost when a language dies? (Not just communication — knowledge systems, cognitive frameworks, biodiversity knowledge in indigenous languages.) (E) Is language preservation always possible or desirable? What about the speaker community''s own preferences?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Neuroscience of Decision Making', 'knowledge', '{"question": "Explain how the human brain makes decisions, integrating multiple levels of analysis: (A) Neurotransmitter level — dopamine''s role in prediction error and reward learning, serotonin in patience and long-term thinking. (B) Brain region level — prefrontal cortex vs. amygdala, the somatic marker hypothesis (Damasio), and why brain damage to specific areas produces specific decision-making deficits. (C) Cognitive level — Kahneman''s System 1/System 2, specific biases and their neural correlates. (D) Social level — how group dynamics change individual decision-making (conformity studies, groupthink). (E) Implications: given what we know, is ''rational'' decision-making possible? What does ''rational'' even mean neuroscientifically? (F) How should this knowledge change how we design institutions, voting systems, and AI assistants?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'History of Cryptography', 'knowledge', '{"question": "Trace the history of cryptography from ancient to modern: (A) Caesar cipher and frequency analysis — why simple substitution fails. (B) The Enigma machine — explain the mechanical encryption, the mathematical problem, and exactly how Turing and the Bomba/Bombe broke it. Why was the Polish contribution critical? (C) The Diffie-Hellman revolution — explain how public key cryptography solved the key distribution problem. Include the discrete logarithm problem. (D) RSA — explain the algorithm, why it works (factoring is hard), and why quantum computing threatens it. (E) Post-quantum cryptography — what lattice-based cryptography is and why it might survive quantum attacks. For each era, explain what threat model the cryptography was designed for."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Ecology: Trophic Cascades', 'knowledge', '{"question": "Explain trophic cascades using three detailed real-world examples: (A) The reintroduction of wolves to Yellowstone — trace the cascade from wolves → elk behavior → riparian vegetation → river morphology → songbirds. Separate confirmed science from popular exaggeration. (B) The near-extinction of sea otters in the Aleutian Islands — otter → sea urchin → kelp forest → fish populations → eagle diet changes. (C) The removal of sharks from coral reefs — predator loss → mesopredator release → herbivore decline → algal takeover. For each: explain the mechanism, quantify the effects where possible, discuss confounding variables that complicate the narrative, and explain why simple ''put the predator back'' solutions sometimes fail."}', '{}', 'medium', now()),
(gen_random_uuid(), 'Economics: Market Failures', 'knowledge', '{"question": "Explain the four main types of market failure with detailed real-world examples: (A) Externalities — carbon emissions, antibiotic resistance. For each, explain why the market price is ''wrong'' and quantify the externality if possible. (B) Public goods — national defense, basic research. Explain the free-rider problem and why private provision fails. (C) Information asymmetry — health insurance adverse selection, used car lemons. Explain the market unraveling mechanism. (D) Market power — tech platform monopolies. Explain network effects and how they create natural monopolies. For each type: evaluate government interventions (taxes, regulation, provision) and their own failure modes (government failure). When is the cure worse than the disease?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Anthropology: Cargo Cults', 'knowledge', '{"question": "Analyze cargo cult phenomena as a lens for understanding how humans make sense of technology and power: (A) Describe the original cargo cults of Melanesia — what specifically did islanders do and why was it rational given their knowledge? (B) Explain ''cargo cult science'' (Feynman''s term) — what makes something cargo cult science vs. real science? Give 3 modern examples. (C) ''Cargo cult programming'' — copying code patterns without understanding them. Why is this so common and what are the consequences? (D) Cargo cult management — adopting processes from successful companies without understanding context. (E) What do cargo cults teach us about human cognition — our instinct to find patterns, attribute causation, and create ritual? Is all culture a form of cargo cult behavior?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Astronomy: The Drake Equation', 'knowledge', '{"question": "Use the Drake Equation as a framework for estimating the number of detectable civilizations in our galaxy: (A) State each parameter and provide your best estimate with uncertainty ranges: star formation rate, fraction with planets, habitable planets per system, fraction where life arises, fraction that develops intelligence, fraction that develops technology, and civilization lifetime. (B) For each parameter, explain what evidence constrains the estimate (Kepler data, extremophile biology, etc.). (C) Which parameters are we most uncertain about and why? (D) Calculate N for optimistic, pessimistic, and ''best guess'' scenarios. (E) Address the Fermi Paradox — if N is large, where is everyone? Evaluate 3 proposed solutions (Great Filter, Zoo Hypothesis, Dark Forest). (F) What would the discovery of microbial life on Mars or Europa do to the equation?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Philosophy of Mathematics: What Are Numbers?', 'knowledge', '{"question": "Explore the ontological status of mathematical objects: (A) Platonism — numbers exist independently of minds. What evidence supports this? (The ''unreasonable effectiveness of mathematics'' in physics.) (B) Formalism — mathematics is just symbol manipulation by rules. Can this account for mathematical truth? (C) Intuitionism — mathematics is a mental construction. What does this mean for the law of excluded middle and proof by contradiction? (D) Structuralism — mathematical objects are just positions in structures. Does this solve the problem? (E) Apply to a specific case: does the number π exist? In what sense? What about uncomputable real numbers that can never be written down? (F) Does it matter to working mathematicians which philosophy is correct?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Medical History: Germ Theory Revolution', 'knowledge', '{"question": "Trace the discovery and acceptance of germ theory: (A) Pre-germ theory explanations for disease (miasma theory, humoral theory) — why were they plausible given available evidence? (B) Key contributors and their specific discoveries: Semmelweis (handwashing), Pasteur (fermentation/vaccination), Koch (postulates), Lister (antiseptic surgery). What resistance did each face and why? (C) How long did it take from initial evidence to widespread acceptance? Why the delay? (D) The specific case of cholera: John Snow''s epidemiological detective work vs. the medical establishment. (E) What modern medical beliefs might be our era''s ''miasma theory'' — accepted now but wrong? How would we know? (F) What does the germ theory revolution teach us about paradigm change in science?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Geopolitics: Chokepoints', 'knowledge', '{"question": "Analyze the world''s strategic maritime chokepoints and their geopolitical significance: (A) Strait of Hormuz — what fraction of global oil passes through it? Who controls it? What happens if it''s blocked? (B) Strait of Malacca — significance for East Asian economies, China''s ''Malacca Dilemma,'' and the String of Pearls strategy. (C) Suez Canal — the 2021 Ever Given blockage as a case study in fragile supply chains. Cost analysis of the disruption. (D) Panama Canal — drought-related transit restrictions and implications for global trade. (E) Taiwan Strait — semiconductor supply chain vulnerability. (F) For each chokepoint: what are the alternative routes, how much do they cost, and who is most affected by disruption? What does chokepoint analysis tell us about the vulnerability of globalization?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Food Science: Fermentation', 'knowledge', '{"question": "Explain the science of fermentation across cultures: (A) The biochemistry — what are microorganisms actually doing during fermentation? Explain glycolysis, the Krebs cycle (or lack thereof in anaerobic conditions), and why fermentation produces alcohol, acids, or gases. (B) Bread — yeast fermentation, gluten development, sourdough starter microbial ecology. Why does sourdough taste different from commercial bread? (C) Cheese — the role of specific bacteria and molds. Why does Roquefort taste completely different from Cheddar at the molecular level? (D) Fermented vegetables — kimchi, sauerkraut, pickles. What determines whether fermentation produces safe food vs. dangerous botulism? (E) Alcohol — wine, beer, spirits. The role of yeast strain selection. (F) Why did nearly every civilization independently develop fermentation?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Computing History: Unix Philosophy', 'knowledge', '{"question": "Explain the Unix philosophy and its lasting impact on computing: (A) The original principles — ''do one thing well,'' pipes and filters, text as universal interface. Why were these radical in 1969? (B) How Unix influenced: the internet (BSD sockets, TCP/IP implementation), open source (GNU, Linux), modern DevOps (containerization, microservices). (C) Where Unix philosophy conflicts with modern software design — why do we have monolithic applications, GUIs, and binary formats? (D) The ''worse is better'' essay — explain Gabriel''s argument and why simplicity in implementation can beat correctness. (E) Compare Unix philosophy with other approaches: Plan 9 (Unix taken to its logical conclusion), Windows (integrated design), and mobile OS design (sandboxed apps). Which approach ''won'' and why?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Psychology: The Stanford Prison Experiment Reassessed', 'knowledge', '{"question": "Critically analyze the Stanford Prison Experiment in light of modern revelations and replication failures: (A) Describe the original experiment, its findings, and Zimbardo''s conclusions about situational power. (B) Detail the methodological problems revealed by later investigation: researcher coaching of guards, selection bias, demand characteristics, and the lack of a true control group. (C) What do the BBC Prison Study and other replications show about the original conclusions? (D) Does the debunking mean ''situations don''t matter''? No — explain what we actually know about situational vs. dispositional factors in behavior (Milgram''s obedience studies, Abu Ghraib). (E) What does this case study teach us about: how psychology textbooks perpetuate debunked findings, the replication crisis, and the danger of dramatic narratives in science?"}', '{}', 'medium', now()),
(gen_random_uuid(), 'Comparative Religion: Death and Afterlife', 'knowledge', '{"question": "Compare how major world religions and philosophical traditions conceive of death and what (if anything) follows: (A) Christianity — heaven/hell, bodily resurrection, the problem of infant damnation, and how different denominations disagree. (B) Islam — barzakh (intermediate state), judgment day, jannah/jahannam, and the concept of divine mercy. (C) Hinduism — samsara, karma across lifetimes, moksha as liberation from the cycle. (D) Buddhism — rebirth without a soul (anatta + rebirth paradox), nirvana, and the intermediate state (bardo) in Tibetan Buddhism. (E) Secular/atheist — the Epicurean argument (''death is nothing to us''), existentialist acceptance, and transhumanist rejection. (F) How does each tradition''s view of death shape its adherents'' behavior in life? Include one surprising similarity between traditions that seem completely different."}', '{}', 'hard', now()),
(gen_random_uuid(), 'Engineering: Bridge Failures', 'knowledge', '{"question": "Analyze three famous bridge failures and what each taught civil engineering: (A) Tacoma Narrows (1940) — aeroelastic flutter. Explain the physics of wind-induced resonance, why the bridge designers didn''t anticipate it, and how modern suspension bridge design prevents it. (B) I-35W Mississippi River Bridge (2007) — gusset plate failure. Explain the role of inspection regimes, design load vs. actual load over time, and the corrosion-fatigue interaction. (C) Morandi Bridge in Genoa (2018) — cable-stayed concrete degradation. Explain prestressed concrete, chloride-induced corrosion, and why the design made inspection difficult. For each: what specific engineering code or practice changed as a result? What bridges today might have similar undetected problems?"}', '{}', 'hard', now()),
(gen_random_uuid(), 'Information Theory Explained', 'knowledge', '{"question": "Explain Shannon''s information theory and its profound implications: (A) What is ''information'' mathematically? Explain entropy, bits, and the relationship between probability and information content. (B) The noisy channel theorem — what does it mean that error-free communication is possible over a noisy channel? Why was this surprising? (C) Data compression — explain Huffman coding and why you can''t compress random data. What does this have to do with information entropy? (D) Connection to thermodynamics — Maxwell''s demon, Landauer''s principle, and why information is physical. (E) Applications beyond communication: information theory in biology (DNA as information), neuroscience (neural coding), machine learning (cross-entropy loss), and gambling (Kelly criterion). (F) What would Shannon think about modern AI?"}', '{}', 'hard', now());
